package main

import (
	"fmt"
	"time"

	"github.com/robertkrimen/otto"
)

const (
	// DefaultScriptTimeout is the maximum time a script can run per item
	DefaultScriptTimeout = 5 * time.Second
)

// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
// The script should evaluate to a truthy or falsy value; items for which the script is truthy are included in the result.
// Security: A timeout is applied to each script execution to prevent infinite loops and resource exhaustion.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	return FilterItemsWithTimeout(conditionScript, items, DefaultScriptTimeout)
}

// FilterItemsWithTimeout filters items with a custom timeout for script execution.
// This provides protection against malicious or poorly written scripts that could cause
// infinite loops or excessive resource consumption.
func FilterItemsWithTimeout(conditionScript string, items []map[string]interface{}, timeout time.Duration) ([]map[string]interface{}, error) {
	// Handle nil or empty input
	if items == nil {
		return nil, fmt.Errorf("items cannot be nil")
	}

	if len(items) == 0 {
		return []map[string]interface{}{}, nil
	}

	var result []map[string]interface{}

	// Create VM once for efficiency (avoid creating a new VM for each item)
	// This prevents resource exhaustion when processing large datasets
	vm := otto.New()

	for _, item := range items {
		value, err := executeScriptSafely(vm, conditionScript, item, timeout)
		if err != nil {
			return nil, fmt.Errorf("error processing item: %w", err)
		}

		// Convert result to boolean using JavaScript truthiness
		boolResult, err := value.ToBoolean()
		if err != nil {
			return nil, fmt.Errorf("error converting result to boolean: %w", err)
		}

		if boolResult {
			result = append(result, item)
		}
	}

	return result, nil
}

// executeScriptSafely executes a JavaScript script with timeout protection and panic recovery.
// This prevents malicious or buggy scripts from causing denial of service or application crashes.
func executeScriptSafely(vm *otto.Otto, script string, item map[string]interface{}, timeout time.Duration) (otto.Value, error) {
	// Set up interrupt channel for timeout mechanism
	// This allows us to forcefully stop long-running scripts
	vm.Interrupt = make(chan func(), 1)

	// Start timeout handler in a separate goroutine
	go func() {
		time.Sleep(timeout)
		// Send interrupt function to stop the VM
		select {
		case vm.Interrupt <- func() {
			// This panic will be caught by the recover below
			panic("script execution timeout exceeded")
