// Default timeout for script execution to prevent DoS attacks
const defaultScriptTimeout = 5 * time.Second

// ErrScriptTimeout is returned when script execution exceeds the timeout
var ErrScriptTimeout = errors.New("script execution timeout")

// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
// The script should evaluate to a truthy or falsy value; items for which the script is truthy are included in the result.
//
// Security improvements:
// - Script is compiled once to validate syntax before processing items
// - Script execution has a timeout to prevent infinite loops (DoS attacks)
// - VM is reused for better performance and reduced resource consumption
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	var result []map[string]interface{}

	// Create a single VM instance for efficiency
	vm := otto.New()

	// Compile the script once for validation and efficiency
	// This catches syntax errors before processing any items
	script, err := vm.Compile("", conditionScript)
	if err != nil {
		return nil, err
	}

	for _, item := range items {
		// Run script with timeout protection
		value, err := runScriptWithTimeout(vm, script, item, defaultScriptTimeout)
		if err != nil {
			// Check if the error is due to timeout
			if strings.Contains(err.Error(), ErrScriptTimeout.Error()) {
				return nil, ErrScriptTimeout
			}
			return nil, err
		}

		// Convert result to boolean using JavaScript truthiness
		boolResult, err := value.ToBoolean()
		if err != nil {
			return nil, err
		}

		if boolResult {
			result = append(result, item)
		}
	}

	return result, nil
}

// runScriptWithTimeout executes a script with timeout protection to prevent DoS attacks.
func runScriptWithTimeout(vm *otto.Otto, script *otto.Script, item map[string]interface{}, timeout time.Duration) (otto.Value, error) {
	// Create interrupt channel for this execution
	interrupt := make(chan func(), 1)
	vm.Interrupt = interrupt

	// Create done channel to signal completion and prevent goroutine leak
	done := make(chan struct{})

	// Start timeout goroutine
	go func() {
		select {
		case <-time.After(timeout):
			// Timeout reached, interrupt the VM
			interrupt <- func() {
				panic(ErrScriptTimeout)
			}
		case <-done:
			// Script completed before timeout, no action needed
		}
	}()

	// Set the item variable in the VM context
	if err := vm.Set("item", item); err != nil {
		close(done)
		return otto.Value{}, err
	}

	// Run the compiled script
	value, err := vm.Run(script)
	close(done) // Signal completion to timeout goroutine

	return value, err
}

