// Default timeout for script execution to prevent DoS attacks
const defaultScriptTimeout = 5 * time.Second

// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
// The script should evaluate to a truthy or falsy value; items for which the script is truthy are included in the result.
//
// Security measures implemented:
//   - Script execution timeout to prevent infinite loops and DoS attacks
//   - Each item is processed in an isolated VM context to prevent state leakage between items
//   - Panic recovery to handle unexpected script errors gracefully
func FilterItems(conditionScript string, items []map[string]interface{}) (result []map[string]interface{}, err error) {
	// Pre-validate and compile the script once
	tmpVM := otto.New()
	compiledScript, err := tmpVM.Compile("", conditionScript)
	if err != nil {
		return nil, fmt.Errorf("script compilation failed: %w", err)
	}

	for _, item := range items {
		// Create a fresh VM for each item to ensure isolation and prevent state leakage
		vm := otto.New()

		// Inject the current item as a global variable named 'item'
		if err := vm.Set("item", item); err != nil {
			return nil, fmt.Errorf("failed to set item variable: %w", err)
		}

		// Set up a timeout to interrupt long-running or malicious scripts
		// This prevents DoS attacks via infinite loops or computationally expensive operations
		timeout := time.AfterFunc(defaultScriptTimeout, func() {
			vm.Interrupt <- func() { panic("script execution timeout exceeded") }
		})

		// Use defer with recover for panic protection
		func() {
			defer func() {
				if r := recover(); r != nil {
					err = fmt.Errorf("script execution panic: %v", r)
				}
				timeout.Stop()
			}()

			// Run the compiled condition script
			var value otto.Value
			value, err = vm.Run(compiledScript)
			if err != nil {
				return
			}

			// Convert result to boolean using JavaScript truthiness
			var boolResult bool
			boolResult, err = value.ToBoolean()
			if err != nil {
				return
			}

			if boolResult {
				result = append(result, item)
			}
		}()

		if err != nil {
			return nil, err
		}
	}

	return result, nil
}

